## NHEFS-based semi-synthetic experiment.
##
## This script expects nhefs_covariates_prepared.csv, generated by
## scripts/00_prepare_nhefs_covariates.R. If the file is absent, the script
## stops with an instruction rather than silently using artificial data.

source("ra_aipw_functions.R")


x_path <- "nhefs_covariates_prepared.csv"

if (!file.exists(x_path)) {
  stop(
    "Prepared NHEFS covariate file not found. ",
    "Place the covariate CSV at nhefs_covariates.csv or set NHEFS_CSV, ",
    "then run scripts/00_prepare_nhefs_covariates.R."
  )
}

set.seed(20260613)

xdat <- read.csv(x_path)
xmat <- as.matrix(xdat)
n <- nrow(xmat)

if (n < 50) {
  stop("The prepared NHEFS covariate matrix has too few rows.")
}

## Construct a low-dimensional score from the observed covariate distribution.
score1 <- as.numeric(scale(xmat[, 1]))
score2 <- if (ncol(xmat) >= 2) as.numeric(scale(xmat[, 2])) else score1^2
score3 <- if (ncol(xmat) >= 3) as.numeric(scale(xmat[, 3])) else pmax(score1, 0)

make_nhefs_semisynthetic <- function(kappa, seed = NULL) {
  if (!is.null(seed)) set.seed(seed)

  lin <- -kappa * score1 + 0.25 * score2
  a <- uniroot(function(a0) mean(expit(a0 + lin)) - 0.5,
               lower = -20, upper = 20)$root
  e <- expit(a + lin)
  r <- rbinom(n, size = 1, prob = e)

  mu <- 1 + 0.40 * score1 - 0.25 * score2 +
    0.75 * pmax(score1, 0) + 0.30 * score3
  y_full <- mu + rnorm(n)
  y_obs <- ifelse(r == 1, y_full, 0)

  list(
    x = score1,
    r = r,
    y = y_obs,
    y_full = y_full,
    e = e,
    mu = mu,
    psi_true = mean(y_full)
  )
}

kappa_grid <- c(0, 1, 2, 3)
rho_values <- c(0.05, 0.10, 0.20, 0.40, 0.60)
tau <- 0.20
n_reps <- 100

all_results <- list()
counter <- 1

for (kappa in kappa_grid) {
  message("NHEFS semi-synthetic experiment: kappa = ", kappa)

  for (rep in seq_len(n_reps)) {
    dat <- make_nhefs_semisynthetic(kappa, seed = 300000 + 1000 * kappa + rep)
    folds <- make_folds(n, k = 5, seed = 400000 + rep)

    z <- evaluate_methods(
      dat,
      tau = tau,
      rho_values = rho_values,
      cutoff_fixed = 0.05,
      folds = folds
    )
    z$kappa <- kappa
    z$rep <- rep
    all_results[[counter]] <- z
    counter <- counter + 1
  }
}

raw <- do.call(rbind, all_results)

summary_list <- lapply(split(raw, list(raw$kappa, raw$method), drop = TRUE), function(z) {
  data.frame(
    kappa = unique(z$kappa),
    method = unique(z$method),
    bias = mean(z$estimate - z$psi_true, na.rm = TRUE),
    rmse = sqrt(mean((z$estimate - z$psi_true)^2, na.rm = TRUE)),
    coverage = mean(z$covered, na.rm = TRUE),
    q99_abs_phi = mean(z$q99_abs_phi, na.rm = TRUE),
    active = mean(z$active, na.rm = TRUE),
    rel_mass = mean(z$rel_mass, na.rm = TRUE)
  )
})

summary_df <- do.call(rbind, summary_list)
summary_df <- summary_df[order(summary_df$kappa, summary_df$method), ]

write.csv(raw, "nhefs_semisynthetic_raw.csv", row.names = FALSE)
write.csv(summary_df, "nhefs_semisynthetic_summary.csv", row.names = FALSE)

plot_metric(summary_df, "kappa", "rmse", "method",
            "fig_rmse_vs_kappa_color.png",
            ylab = "RMSE", xlab = expression(kappa))

plot_metric(summary_df, "kappa", "q99_abs_phi", "method",
            "fig_tail_q99_vs_kappa_color.png",
            ylab = expression(q[0.99](abs(phi[i]))),
            xlab = expression(kappa))

message("Wrote NHEFS semi-synthetic outputs to  and .")
